INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at)
VALUES ('1212832868560339', 'Portfolio Consolidation', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', CAST('2026-06-30' AS DATE), NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, CAST('{"1211898465243458": {"name": "Status C-week", "value": "Not Started"}, "1209637014993158": {"name": "Notes - Task", "value": "In alignment with Google\ufffd\ufffd\ufffds best practices and smart bidding protocols, we will consolidate split portfolios into a more cohesive structure, with the objective of enhancing signal quality for Google\ufffd\ufffd\ufffds algorithms and ensuring alignment with smart bidding optimization best practices. \n\nThe team plans to test this approach in Q1 by combining two portfolios into one in the DE market.\n\n"}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}}' AS JSON), CURRENT_TIMESTAMP), ('1212832868560333', 'AMO Objective Change Test', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', CAST('2026-04-30' AS DATE), NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, CAST('{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "The implementation was initiated for a subset of IT portfolios on 1/5, with the remaining portfolios migrated on 1/15. Following the implementation of the new feed, data discrepancies between our dashboard and AMO decreased from -23% to +6% avg in IT, significantly improving reporting accuracy and insight quality. While the bidding objective change in IT has not yet driven incremental lift, the enhanced data reliability positions us well for more informed optimization decisions. We have also transitioned our reporting to align with the new registrations objective (and transitioned the portfolios currently using Daily spend target to the new objectives in EU2 on 3/3/26). Data will continue to inform optimizations post OCI implementation."}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "0"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}}' AS JSON), CURRENT_TIMESTAMP), ('1212832868339127', 'Evidence Based Ad Copy Test', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', CAST('2026-12-31' AS DATE), NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, CAST('{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "Evidence-based ad copy testing is currently underway in the UK (launched 1/29) and IT (launched 2/19). We anticipate an increase in click-through rates, alongside an incremental rise in registrations, with a before and after lift of 85 regs in initial UK results and +3% CVR lift and improved CTR (15% control vs 28% test). In IT was saw a 15% lift in CTR. Due to success we rolled out Phase 2 in UK and IT (100% of NB) ahead of schedule, with phased rollouts scheduled across the EU in Q3 and Q4 2026 - post OCI implementation. Projected registration impact is included in OCI reg projections and not incremental lift.\n"}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "2000"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "EU5"}}' AS JSON), CURRENT_TIMESTAMP), ('1212832868339125', 'Campaign Consolidation', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', CAST('2026-12-31' AS DATE), NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, CAST('{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "Account consolidation is underway in OCI regions, with EU3 slated for August after OCI implementation is complete. \n\nUK and DE Product and Vertical campaigns have been consolidated in January 2026 to streamline the account and reduce management overhead."}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "EU5"}}' AS JSON), CURRENT_TIMESTAMP), ('1212832868339115', 'OCI Implementation', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', CAST('2026-08-31' AS DATE), NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, CAST('{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "PS team has transitioned EU3 billing + accounts into the OCI MCC. Tech is on track for readiness with tracking testing beginning 2/26 and continuing through the end of March. Post tracking implementation our team will begin a 4 week learning period within Google while continuing to utilize AMO bidding objectives. \n\nFull transition to OCI planned for May 2026. "}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "0"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "FR, ES, IT, CA, JP"}}' AS JSON), CURRENT_TIMESTAMP), ('1213917771155873', '���� Paid App ��� Project Context (Kiro)', '1212732742544167', 'Paid App', '1205997667578886', 'Backlog', NULL, NULL, FALSE, NULL, 'Core', 'Not urgent', NULL, '4/3: Project context doc. Pinned reference ��� not a task to complete. Updated by agent during EOD-2 system refresh.', NULL, CAST('2026-04-02' AS DATE), NULL, CURRENT_TIMESTAMP)
